          entry.lbs = Math.round((entry.lbs + harvested) * 10) / 10;
          entry.jars = (entry.jars || 0) + Math.max(1, Math.round(harvested)); // ~1 lb per jar
          entry.lastDay = day;
          newVarietals[varietal.id] = entry;
