            c.beginPath(); c.arc(hdX - bee(25), hdY - bee(60), bee(3), 0, 6.28); c.fill();
            c.beginPath(); c.arc(hdX + bee(5), hdY - bee(58), bee(3), 0, 6.28); c.fill();
