            c.beginPath(); c.moveTo(hdX - bee(15), hdY - bee(55));
            c.quadraticCurveTo(hdX - bee(40), hdY - bee(90), hdX - bee(65), hdY - bee(80)); c.stroke();
            // Antenna tips
