              var dist = Math.sqrt((ds.x - q.x) * (ds.x - q.x) + (ds.y - q.y) * (ds.y - q.y) + (ds.z - q.z) * (ds.z - q.z));
              c.font = 'bold 9px system-ui'; c.fillStyle = '#fef3c7';
              c.fillText(Math.round(dist) + 'm', p.x, p.y + 10 * p.s);
